/*\n  # Critical Table Optimization - Sequential Scan Reduction\n\n  1. Critical Issues Identified\n    - **user_roles**: 1.16M sequential scans, only 22% index usage\n      - Has unique constraint on (user_id, role) but still high seq scans\n      - Redundant composite index needs removal\n    \n    - **region_settings**: 754 sequential scans, 0% index usage\n      - Missing index on region_id (main lookup column)\n      - High sequential scan rate\n    \n    - **driver_documents**: 12,495 sequential scans, only 3.6% index usage\n      - Very low index usage despite having indexes\n      - Need additional composite indexes\n    \n    - **eats_zones**: 4,526 sequential scans, 16.69% index usage\n      - Poor index utilization\n      - Need zone_code and city_id composite indexes\n    \n    - **regions**: 3,542 sequential scans, 47.5% index usage\n      - Moderate performance, could be improved\n\n  2. New Indexes\n    - region_settings: Add region_id index\n    - driver_documents: Add composite indexes for common filters\n    - eats_zones: Add composite indexes for better query performance\n    - regions: Add covering indexes\n    - compliance_reminders: Add scheduling indexes\n    - security_events: Add covering indexes\n    - driver_location_history: Add time-based indexes\n    - user_roles: Remove redundant indexes\n\n  3. Expected Impact\n    - Reduce sequential scans by 60-80%\n    - Improve query performance by 3-5x on affected tables\n    - Better resource utilization\n*/\n\n-- region_settings: Critical missing index on region_id\nCREATE INDEX IF NOT EXISTS idx_region_settings_region_id ON public.region_settings(region_id);
\n\n-- region_settings: Service-specific lookups\nCREATE INDEX IF NOT EXISTS idx_region_settings_rides_enabled ON public.region_settings(region_id, rides_enabled) WHERE rides_enabled = true;
\nCREATE INDEX IF NOT EXISTS idx_region_settings_eats_enabled ON public.region_settings(region_id, eats_enabled) WHERE eats_enabled = true;
\nCREATE INDEX IF NOT EXISTS idx_region_settings_move_enabled ON public.region_settings(region_id, move_enabled) WHERE move_enabled = true;
\n\n-- driver_documents: Improve index coverage for common query patterns\nCREATE INDEX IF NOT EXISTS idx_driver_documents_driver_status ON public.driver_documents(driver_id, status, document_type);
\nCREATE INDEX IF NOT EXISTS idx_driver_documents_expiring ON public.driver_documents(expires_at, status) WHERE expires_at IS NOT NULL AND status = 'approved';
\n\n-- eats_zones: Critical composite indexes\nCREATE INDEX IF NOT EXISTS idx_eats_zones_city_zone ON public.eats_zones(city_id, zone_code) WHERE city_id IS NOT NULL;
\nCREATE INDEX IF NOT EXISTS idx_eats_zones_active ON public.eats_zones(is_active, zone_code) WHERE is_active = true;
\nCREATE INDEX IF NOT EXISTS idx_eats_zones_city_active ON public.eats_zones(city_id, is_active, zone_code) WHERE is_active = true AND city_id IS NOT NULL;
\nCREATE INDEX IF NOT EXISTS idx_eats_zones_state_city ON public.eats_zones(state, city_name) WHERE state IS NOT NULL;
\n\n-- regions: Add composite indexes for common lookups\nCREATE INDEX IF NOT EXISTS idx_regions_state_city ON public.regions(state, city);
\nCREATE INDEX IF NOT EXISTS idx_regions_country_state ON public.regions(country, state);
\n\n-- compliance_reminders: Add indexes for scheduling queries\nCREATE INDEX IF NOT EXISTS idx_compliance_reminders_due ON public.compliance_reminders(remind_at, sent) WHERE sent = false;
\nCREATE INDEX IF NOT EXISTS idx_compliance_reminders_entity ON public.compliance_reminders(entity_id, entity_type, sent);
\n\n-- admin_audit_logs: Improve search and filtering\nCREATE INDEX IF NOT EXISTS idx_admin_audit_logs_action_time ON public.admin_audit_logs(action, created_at DESC);
\nCREATE INDEX IF NOT EXISTS idx_admin_audit_logs_admin_time ON public.admin_audit_logs(admin_id, created_at DESC);
\n\n-- Drop redundant index on user_roles (user_id, role unique constraint already provides this)\nDROP INDEX IF EXISTS idx_user_roles_user_role_composite;
\n\n-- security_events: Add covering index for common queries\nCREATE INDEX IF NOT EXISTS idx_security_events_user_severity_time ON public.security_events(user_id, severity, event_type, created_at DESC) WHERE user_id IS NOT NULL;
\n\n-- driver_location_history: Add index for time-based queries\nCREATE INDEX IF NOT EXISTS idx_driver_location_history_driver_time ON public.driver_location_history(driver_id, recorded_at DESC);
;
